class Solution {
public:
    string smallestEquivalentString(string s1, string s2, string baseStr) {
        unordered_map<char, char> mapping;
        for (int i = 0; i < s1.size(); i++) {
            mapping[s1[i]] = s2[i];
        }
        string result = "";
        for (char c : baseStr) {
            result += mapping.count(c) ? mapping[c] : c;
        }
        return result;
    }
};
